/* In your theme */
:root {
--skeleton-base: 229 231 235; /* neutral-200 */
--skeleton-highlight: 243 244 246; /* neutral-100 */
}
.dark {
--skeleton-base: 38 38 38; /* neutral-800 */
--skeleton-highlight: 55 55 55; /* neutral-700 */
}

